func parameterHasNotes(param APIParameter) bool {
	return param.DescriptionHTML != "" || schemaHasNotes(param.Schema)
}

func schemaHasNotes(schema APISchema) bool {
	return schema.DescriptionHTML != "" || schema.HasConst || len(schema.EnumValues) > 0 || schema.Format != "" || schema.MaxItems != nil || schema.MinItems != nil
}

func openAPIDescription(descriptionHTML string, class string) templ.Component {
	return templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		if err := ctx.Err(); err != nil {
			return err
		}

		if descriptionHTML == "" {
			return nil
		}

		classes := strings.TrimSpace("max-w-prose space-y-3 " + class)
		if _, err := io.WriteString(w, `<div class="`+stdhtml.EscapeString(classes)+`">`); err != nil {
			return err
		}
		if _, err := io.WriteString(w, descriptionHTML); err != nil {
			return err
		}
		_, err := io.WriteString(w, "</div>")
		return err
	})
}

func methodSampleEndpoint(method APIMethod) string {
	values := []string{}
	for _, param := range method.Parameters {
		if param.In != "query" || !param.Required {
			continue
		}
		values = append(values, param.Name+"="+strings.ToUpper(param.Name))
	}
	if len(values) == 0 {
		return method.Endpoint
	}
	return method.Endpoint + "?" + strings.Join(values, "&")
}

func methodCurlExample(ctx context.Context, method APIMethod) string {
	endpoint := methodAbsoluteSampleEndpoint(ctx, method)
	command := "curl"
	if method.HTTPMethod != "GET" {
		command += " -X " + method.HTTPMethod
	}

	lines := []string{command}
	if method.Authorization == "Bearer token" {
		lines = append(lines, "  -H 'Authorization: Bearer YOUR_API_TOKEN'")
	}
	lines = append(lines, "  '"+endpoint+"'")
	return strings.Join(lines, " \\\n")
}

func methodAbsoluteSampleEndpoint(ctx context.Context, method APIMethod) string {
	endpoint := methodSampleEndpoint(method)
	parsed, err := url.Parse(endpoint)
	if err != nil {
		panic(err)
	}
	if parsed.IsAbs() {
		return endpoint
	}

	baseURL := reqcontext.BaseURLFromContext(ctx)
	if baseURL == "" {
		return endpoint
	}
	return strings.TrimRight(baseURL, "/") + "/" + strings.TrimLeft(endpoint, "/")
}

